-- {"operators": "INNER_JOIN,FILTER", "complexity": "medium", "is_incremental": true, "has_nulls": false, "has_cast": false, "has_case": false, "tables": "DISTRICT,CUSTOMER", "ducklake": true}
SELECT c.C_W_ID, c.C_ID, c.C_DISCOUNT, c.C_CREDIT_LIM, (c.C_CREDIT_LIM * c.C_DISCOUNT) AS max_discount_value FROM dl.CUSTOMER c JOIN dl.DISTRICT d ON c.C_W_ID = d.D_W_ID AND c.C_D_ID = d.D_ID WHERE c.C_DISCOUNT > 0;
